/// <summary>
/// Extension of the <c>init</c> method for the ETGSPAIN model.
/// </summary>
/// <remarks>
/// This code is used to show or hide features in Spanish companies.
/// </remarks>
public void init()
{
    next init();
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(SrmParameters, ETGSPAINAgreementUpdates)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SrmParameters, ETGSPAINAgreementUpdates_ETGSPAINPurchPlateHourUpdate)).visible(currentCompanyIsSpanishCompany);

}
